# include<bits/stdc++.h>
using namespace std;
bool isPrime(int n)
{	
	for(int i=2;i<=sqrt(n);i++){
		if(n%i==0)return false;
	}return true;
}
int main()

{


    int a,sum=0,tot=0;
	cin>>a;
	for(int i=2;i+tot<=a;i++)
	{if(isPrime(i)){
		cout<<i<<endl;
		tot+=i;//总数和
		sum++;//总数
	}


	}cout<<sum<<endl;}
